+import {IgnoreTypes} from '../utils/ignore-types';
+import {Options, RuleType} from '../rules';
+import RuleBuilder, {DropdownOptionBuilder, ExampleBuilder, OptionBuilderBase} from './rule-builder';
+
+type LinkStyleValue = 'no-change' | 'markdown' | 'wiki';
+
+class LinkStyleOptions implements Options {
+  linkStyle: LinkStyleValue = 'no-change';
+  imageStyle: LinkStyleValue = 'no-change';
+}
+
+function unescapeMarkdown(value: string): string {
+  return value.replace(/\\\\(.)/g, '$1');
+}
+
+function defaultHeadingDisplay(target: string): string {
+  const headingIndex = target.indexOf('#');
+  if (headingIndex === -1) return target;
+  const page = target.substring(0, headingIndex);
+  const heading = target.substring(headingIndex + 1);
+  return page ? `${page} > ${heading}` : heading;
+}
+
+function wikiToMarkdown(text: string, convertLinks: boolean, convertImages: boolean): string {
+  return text.replace(/(!?)\\[\\[([^\\]\
]+)\\]\\]/g, (match, embed: string, contents: string) => {
+    if ((embed === '!' && !convertImages) || (embed !== '!' && !convertLinks)) return match;
+    const separator = contents.indexOf('|');
+    const target = separator === -1 ? contents : contents.substring(0, separator);
+    let display = separator === -1 ? defaultHeadingDisplay(target) : contents.substring(separator + 1);
+    if (!target) return match;
+    if (embed === '!') {
+      if (/^\\d+(?:x\\d+)?$/.test(display)) display = '';
+      return `![${display}](${target})`;
+    }
+    return `[${display}](${target})`;
+  });
+}
+
+function closingBracket(text: string, start: number): number {
+  let depth = 1;
+  for (let index = start + 1; index < text.length; index++) {
+    if (text[index] === '\\\') {
+      index++;
+    } else if (text[index] === '[') {
+      depth++;
+    } else if (text[index] === ']' && --depth === 0) {
+      return index;
+    }
+  }
+  return -1;
+}
+
+function closingParen(text: string, start: number): number {
+  let depth = 1;
+  for (let index = start + 1; index < text.length; index++) {
+    if (text[index] === '\\\') {
+      index++;
+    } else if (text[index] === '(') {
+      depth++;
+    } else if (text[index] === ')' && --depth === 0) {
+      return index;
+    }
+  }
+  return -1;
+}
+
+function destination(contents: string): string | null {
+  const trimmed = contents.trim();
+  if (!trimmed || /[\\r\
]/.test(trimmed)) return null;
+  if (trimmed.startsWith('<')) {
+    let end = -1;
+    for (let index = 1; index < trimmed.length; index++) {
+      if (trimmed[index] === '\\\') index++;
+      else if (trimmed[index] === '>') {
+        end = index;
+        break;
+      }
+    }
+    if (end === -1 || trimmed.substring(end + 1).trim()) return null;
+    return unescapeMarkdown(trimmed.substring(1, end));
+  }
+
+  let depth = 0;
+  for (let index = 0; index < trimmed.length; index++) {
+    if (trimmed[index] === '\\\') {
+      index++;
+    } else if (trimmed[index] === '(') {
+      depth++;
+    } else if (trimmed[index] === ')') {
+      depth--;
+    } else if (/\\s/.test(trimmed[index]) && depth === 0) {
+      return null; // Markdown title (or an otherwise unsupported destination form).
+    }
+  }
+  return depth === 0 ? unescapeMarkdown(trimmed) : null;
+}
+
+function markdownToWiki(text: string, convertLinks: boolean, convertImages: boolean): string {
+  let result = '';
+  let cursor = 0;
+  while (cursor < text.length) {
+    const labelStart = text.indexOf('[', cursor);
+    if (labelStart === -1) return result + text.substring(cursor);
+    const image = labelStart > 0 && text[labelStart - 1] === '!';
+    const start = image ? labelStart - 1 : labelStart;
+    result += text.substring(cursor, start);
+    if ((image && !convertImages) || (!image && !convertLinks)) {
+      result += text.substring(start, labelStart + 1);
+      cursor = labelStart + 1;
+      continue;
+    }
+    const labelEnd = closingBracket(text, labelStart);
+    if (labelEnd === -1 || text[labelEnd + 1] !== '(') {
+      result += text.substring(start, labelStart + 1);
+      cursor = labelStart + 1;
+      continue;
+    }
+    const targetEnd = closingParen(text, labelEnd + 1);
+    if (targetEnd === -1) {
+      result += text.substring(start, labelStart + 1);
+      cursor = labelStart + 1;
+      continue;
+    }
+    const label = text.substring(labelStart + 1, labelEnd);
+    const target = destination(text.substring(labelEnd + 2, targetEnd));
+    if (/[\\r\
]/.test(label) || target === null || target.includes('://')) {
+      result += text.substring(start, targetEnd + 1);
+      cursor = targetEnd + 1;
+      continue;
+    }
+    const display = unescapeMarkdown(label);
+    const omitDisplay = display === target || display === defaultHeadingDisplay(target);
+    if (image) {
+      result += `![[${target}${!display || display === target ? '' : `|${display}`}]]`;
+    } else {
+      result += `[[${target}${omitDisplay ? '' : `|${display}`}]]`;
+    }
+    cursor = targetEnd + 1;
+  }
+  return result;
+}
+
+@RuleBuilder.register
+export default class LinkStyle extends RuleBuilder<LinkStyleOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.link-style.name',
+      descriptionKey: 'rules.link-style.description',
+      type: RuleType.CONTENT,
+      ruleIgnoreTypes: [IgnoreTypes.yaml, IgnoreTypes.code, IgnoreTypes.inlineCode, IgnoreTypes.math, IgnoreTypes.inlineMath, IgnoreTypes.html, IgnoreTypes.templaterCommand, IgnoreTypes.obsidianMultiLineComments, IgnoreTypes.table],
+    });
+  }
+
+  get OptionsClass(): new () => LinkStyleOptions { return LinkStyleOptions; }
+
+  apply(text: string, options: LinkStyleOptions): string {
+    const linksToMarkdown = options.linkStyle === 'markdown';
+    const imagesToMarkdown = options.imageStyle === 'markdown';
+    const linksToWiki = options.linkStyle === 'wiki';
+    const imagesToWiki = options.imageStyle === 'wiki';
+    if (linksToMarkdown || imagesToMarkdown) text = wikiToMarkdown(text, linksToMarkdown, imagesToMarkdown);
+    if (linksToWiki || imagesToWiki) text = markdownToWiki(text, linksToWiki, imagesToWiki);
+    return text;
+  }
+
+  get exampleBuilders(): ExampleBuilder<LinkStyleOptions>[] {
+    return [
+      new ExampleBuilder({description: 'Convert wiki links and embeds to Markdown', before: '[[p#h]] ![[f.png|300x200]]', after: '[p > h](p#h) ![](f.png)', options: {linkStyle: 'markdown', imageStyle: 'markdown'}}),
+      new ExampleBuilder({description: 'Convert Markdown links and images to wiki syntax', before: '[d](t) ![alt](f.png)', after: '[[t|d]] ![[f.png|alt]]', options: {linkStyle: 'wiki', imageStyle: 'wiki'}}),
+    ];
+  }
+
+  get optionBuilders(): OptionBuilderBase<LinkStyleOptions>[] {
+    const records = [
+      {value: 'no-change' as LinkStyleValue, description: 'Leave this type of link unchanged'},
+      {value: 'markdown' as LinkStyleValue, description: 'Use Markdown link syntax'},
+      {value: 'wiki' as LinkStyleValue, description: 'Use Obsidian wiki link syntax'},
+    ];
+    return [
+      new DropdownOptionBuilder<LinkStyleOptions, LinkStyleValue>({OptionsClass: LinkStyleOptions, nameKey: 'rules.link-style.link-style.name', descriptionKey: 'rules.link-style.link-style.description', optionsKey: 'linkStyle', records}),
+      new DropdownOptionBuilder<LinkStyleOptions, LinkStyleValue>({OptionsClass: LinkStyleOptions, nameKey: 'rules.link-style.image-style.name', descriptionKey: 'rules.link-style.image-style.description', optionsKey: 'imageStyle', records}),
+    ];
+  }
