    if ((embed === '!' && !convertImages) || (embed !== '!' && !convertLinks)) return match;
    const separator = contents.indexOf('|');
    const target = separator === -1 ? contents : contents.substring(0, separator);
    let display = separator === -1 ? defaultHeadingDisplay(target) : contents.substring(separator + 1);
    if (!target) return match;
    if (embed === '!') {
      if (/^\d+(?:x\d+)?$/.test(display)) display = '';
